.chat-input-row input{
flex:1;border:1px solid #2a3453;border-radius:4px;background:#0a0f1c;color:#dce5fb;font-family:inherit;padding:7px 9px}
.chat-input-row button{
border:1px solid #43527b;border-radius:4px;background:#111a30;color:#dce5fb;font-family:inherit;padding:7px 12px}
.hero-card-stack{
display:flex;flex-direction:column;gap:10px}
.hero-card-preview{
display:flex;gap:12px;align-items:flex-start;border:1px solid #2a3554;border-radius:6px;background:linear-gradient(180deg,#0d1323,#080d1a);padding:12px}
.hero-card-portrait-wrap{
position:relative}
.hero-card-portrait{
width:78px;height:78px}
.hero-card-level{
position:absolute;right:-6px;bottom:-4px;min-width:20px;padding:1px 5px;border:1px solid rgba(255,212,18,.58);border-radius:10px;background:#000c;color:var(--wc3-gold);font-size:.72rem;text-align:center}
.hero-card-body{
flex:1;min-width:0}
.hero-card-head h4{
margin:0;color:var(--wc3-gold);font-size:1rem}
.hero-card-head span{
color:#9cabcf;font-size:.78rem}
.hero-card-bars{
margin-top:8px;display:flex;flex-direction:column;gap:5px}
.hero-card-bar{
position:relative;height:12px;border:1px solid #2f3f68;border-radius:3px;background:#070b14;overflow:hidden}
.hero-card-bar-fill{
position:absolute;inset:0 auto 0 0;height:100%}
.hero-card-bar-fill--hp{
background:linear-gradient(90deg,#3abf3a,#58d869)}
.hero-card-bar-fill--mp{
background:linear-gradient(90deg,#3a58d2,#6280ff)}
.hero-card-bar span{
position:relative;display:block;text-align:center;color:#ecf1ff;font-size:.66rem;line-height:10px;text-shadow:1px 1px 0 rgba(0,0,0,.95)}
.hero-card-stats{
margin-top:8px;display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:4px 10px;color:#b4c0dd;font-size:.73rem}
.hero-card-stats b{
color:#e0e8ff;font-weight:700}
.hero-card-abilities{
margin-top:9px;display:flex;gap:6px}
.hero-card-ability{
width:30px;height:30px;border:1px solid #2b3858;border-radius:3px;background:#0b1120;display:flex;align-items:center;justify-content:center;overflow:hidden;color:#dbe5ff}
.hero-card-ability img{
width:100%;height:100%;display:block}
.hero-card-ability--disabled{
opacity:.45}
.hero-card-compact{
display:inline-flex;align-items:center;gap:8px;border:1px solid #283656;border-radius:6px;background:#090e1a;padding:7px 9px}
.hero-card-compact-portrait{
width:44px;height:44px}
.hero-card-compact-meta{
display:flex;flex-direction:column;line-height:1.15}
.hero-card-compact-meta strong{
color:#e5ecff;font-size:.83rem}
.hero-card-compact-meta span{
color:#98a8cb;font-size:.74rem}
.hero-card-skeleton{
display:flex;align-items:center;gap:10px;border:1px solid #20283e;border-radius:6px;background:#090d18;padding:10px}
.hero-skeleton-avatar{
width:46px;height:46px;border-radius:50%;background:linear-gradient(90deg,#171f33,#25304d,#171f33);background-size:180% 100%;animation:skeleton-shimmer 1.3s linear infinite}
.hero-skeleton-lines{
display:flex;flex-direction:column;gap:5px;width:180px}
.hero-skeleton-lines span{
height:8px;border-radius:4px;background:linear-gradient(90deg,#171f33,#25304d,#171f33);background-size:180% 100%;animation:skeleton-shimmer 1.3s linear infinite}
.hero-skeleton-lines span:nth-child(1){
width:72%}
.hero-skeleton-lines span:nth-child(2){
width:94%}
.hero-skeleton-lines span:nth-child(3){
width:62%}
@keyframes skeleton-shimmer{
0%{
background-position:0% 0}
to{
background-position:180% 0}
}
.esc-checkbox{
position:relative;width:32px;height:32px;border:none;padding:0;background:transparent;cursor:pointer;flex-shrink:0}
.esc-checkbox img{
width:100%;height:100%;display:block;position:absolute;inset:0}
.esc-radio{
position:relative;width:24px;height:24px;border:none;padding:0;background:transparent;cursor:pointer;flex-shrink:0}
.esc-radio img{
width:100%;height:100%;display:block;position:absolute;inset:0}
@media(max-width:900px){
.viewport{
padding:calc(4vw + 12px) 16px 14px}
.footer-worker-unit{
display:none}
.token-grid{
gap:12px}
.token-grid-header{
grid-template-columns:repeat(2,minmax(0,1fr));gap:6px 10px;margin-bottom:0}
.token-grid-header>:first-child{
display:none}
.token-faction-label{
font-size:.64rem}
.token-grid-row{
grid-template-columns:repeat(2,minmax(0,1fr));gap:8px}
.token-name{
grid-column:1 / -1;font-size:.92rem;text-align:left}
.token-swatch{
min-height:40px}
.token-hex{
font-size:.78rem}
.hero-logo{
width:min(320px,55vw)}
.bundle-chart-row{
grid-template-columns:100px 132px 45px}
.bundle-chart{
--bundle-bar-width: 132px}
}
.borders-category{
padding:14px 0 8px;border-top:1px solid rgba(88,104,158,.45)}
.borders-category:first-child{
padding-top:0;border-top:none}
.borders-category-title{
margin:0 0 2px;color:var(--wc3-gold);font-size:.98rem;text-shadow:1px 1px 0 rgba(0,0,0,.9)}
.borders-category-desc{
margin:0 0 10px;color:#7b818d;font-size:.82rem;line-height:1.4}
.borders-grid{
display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:12px}
.border-item{
text-align:center;display:flex;flex-direction:column;align-items:center;gap:6px}
.border-thumbnail{
width:100%;max-width:156px;height:96px;object-fit:contain;image-rendering:pixelated;background:transparent;border-radius:3px}
.border-label{
color:#e2e9ff;font-size:.78rem;line-height:1.2}
.border-filename{
color:#5a6080;font-size:.65rem;word-break:break-all;line-height:1.2}
.borders-loading{
color:#7b818d;font-size:.88rem;text-align:center;padding:24px 0}
@media(max-width:640px){
.borders-grid{
grid-template-columns:repeat(2,minmax(0,1fr));gap:10px 8px}
.border-thumbnail{
max-width:132px;height:84px}
.border-label{
font-size:.74rem}
}
.tooltip-preview-grid{
justify-items:center}

