import React from "react";

export interface MinimapPing {
  x: string;
  y: string;
  color: string;
  delay?: string;
}

export interface MinimapProps {
  /** URL of the minimap image */
  imageUrl?: string;
  /** Ping markers on the minimap */
  pings?: MinimapPing[];
  /** Legend items */
  legend?: { label: string; color: string }[];
  className?: string;
}

/**
 * Minimap frame with fog of war overlay and animated ping markers.
 */
export function Minimap({
  imageUrl,
  pings = [],
  legend = [],
  className,
}: MinimapProps) {
  return (
    <div className={`minimap-showcase ${className ?? ""}`}>
      <div className="minimap-frame">
        {imageUrl && (
          <img className="minimap-image" src={imageUrl} alt="Minimap" />
