              left: ping.x,
              top: ping.y,
              background: ping.color,
              animationDelay: ping.delay ?? "0s",
            }}
          />
        ))}
      </div>
      {legend.length > 0 && (
        <div className="minimap-legend">
          {legend.map((item, i) => (
            <span key={i}>
              <span className="dot" style={{ background: item.color }} />
              {item.label}
            </span>
          ))}
        </div>
      )}
    </div>
  );
}

