import React, { useState } from "react";

export interface DialogAction {
  label: string;
  onClick?: () => void;
  variant?: "primary" | "secondary" | "danger";
}

export interface DialogProps {
  title: string;
  children: React.ReactNode;
  actions?: DialogAction[];
  open?: boolean;
  onClose?: () => void;
  className?: string;
}

/**
 * Modal dialog with WC3 styling, backdrop scrim, and action buttons.
 */
export function Dialog({
  title,
  children,
  actions = [],
  open = false,
  onClose,
  className,
}: DialogProps) {
  if (!open) return null;

  return (
    <div className="dialog-scrim" onClick={onClose}>
      <div
        className={`dialog-preview ${className ?? ""}`}
        onClick={(e) => e.stopPropagation()}
      >
        <h4>{title}</h4>
        <div>{children}</div>
        {actions.length > 0 && (
          <div className="dialog-actions">
            {actions.map((action, i) => (
              <button
                key={i}
                className={`dialog-btn${action.variant ? ` dialog-btn--${action.variant}` : ""}`}
                onClick={action.onClick}
              >
                {action.label}
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

/**
 * Convenience hook for dialog open/close state.
 */
export function useDialog() {
  const [open, setOpen] = useState(false);
  return {
    open,
    show: () => setOpen(true),
    hide: () => setOpen(false),
    toggle: () => setOpen((v) => !v),
  };
}

