  width: min(100%, 384px);
  border: 10px solid transparent;
  border-color: #f4d45e59;
  border-image: var(--tooltip-border) 33.333% fill / 10px;
  background-color: #0a0d16;
  background-image: var(--tooltip-bg);
  background-repeat: repeat;
  background-size: auto;
  padding: 10px 12px;
  color: #f4f7ff;
}
.tooltip-preview--simple {
  width: min(100%, 340px);
}
.tooltip-preview--error {
  color: #eec9c9;
}
.tooltip-preview-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}
.tooltip-preview-head h4 {
  margin: 0;
  color: var(--wc3-gold);
  font-size: 0.72rem;
  line-height: 1.2;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.85);
}
.tooltip-preview p {
  margin: 6px 0 0;
  color: #f1f5ff;
  font-size: 0.72rem;
  line-height: 1.35;
}
.tooltip-hotkey {
  padding: 0;
  color: #fed312;
  font-family: inherit;
  font-size: 0.72rem;
  letter-spacing: 0.01em;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.85);
}
.tooltip-costs {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin-top: 8px;
}
.tooltip-cost {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  color: #fff;
  font-size: 0.72rem;
}
.tooltip-cost img {
  width: 14px;
  height: 14px;
  image-rendering: pixelated;
}
.portrait-showcase {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}
.portrait-stage-wrap {
  position: relative;
  width: min(225px, 52vw);
}
.portrait-stage {
  position: relative;
  width: 100%;
  aspect-ratio: 130 / 160;
  image-rendering: pixelated;
  z-index: 2;
}
.portrait-window {
  position: absolute;
  left: 0;
  top: 0;
  width: 100%;
  height: 100%;
  -webkit-mask-image: var(--portrait-window-mask);
  mask-image: var(--portrait-window-mask);
  -webkit-mask-repeat: no-repeat;
  mask-repeat: no-repeat;
  -webkit-mask-size: 100% 100%;
  mask-size: 100% 100%;
  -webkit-mask-position: center;
  mask-position: center;
  overflow: hidden;
  background: #000;
  z-index: 1;
}
.portrait-frame-overlay {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: fill;
  pointer-events: none;
  z-index: 2;
}
.minimap-showcase {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
}
.minimap-frame {
  position: relative;
  width: 220px;
  height: 220px;
  overflow: hidden;
  border: 2px solid #2a3555;
  box-shadow: inset 0 0 0 1px #ffffff0f;
  background: #090d17;
}
.minimap-image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  opacity: 0.78;
}
.minimap-fog {
  position: absolute;
  inset: 0;
  background: radial-gradient(circle at 50% 50%, #0000 32%, #000000ad);
  pointer-events: none;
}
.minimap-ping {
  position: absolute;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  border: 1px solid rgba(255, 255, 255, 0.75);
  box-shadow: 0 0 #ffffff73;
  animation: minimap-ping 1.8s ease-out infinite;
}
.minimap-ping--a {
  left: 26%;
  top: 34%;
  background: #58d869;
}
.minimap-ping--b {
  left: 61%;
  top: 54%;
  background: #e65a5a;
  animation-delay: 0.6s;
}
.minimap-ping--c {
  left: 47%;
  top: 20%;
  background: #f0d775;
  animation-delay: 1.1s;
}
@keyframes minimap-ping {
  0% {
    box-shadow: 0 0 #ffffff73;
  }
  to {
    box-shadow: 0 0 0 12px #fff0;
  }
}
.minimap-legend {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  justify-content: center;
  color: #9ca8c5;
  font-size: 0.76rem;
}
.minimap-legend span {
  display: inline-flex;
  align-items: center;
  gap: 5px;
}
.dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  display: inline-block;
}
.dot--ally {
  background: #58d869;
}
.dot--enemy {
  background: #e65a5a;
}
.dot--neutral {
  background: #f0d775;
}
.dialog-preview-wrap {
  position: relative;
  min-height: 70px;
}
.dialog-trigger {
  border: 1px solid #44557f;
  border-radius: 4px;
  background: #0f1527;
  color: #dce5fb;
  padding: 8px 12px;
  font-family: inherit;
  cursor: pointer;
}
.dialog-trigger:hover {
  border-color: #6b7fae;
}
.dialog-scrim {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #03050ba6;
  z-index: 50;
}
.dialog-preview {
  width: min(420px, calc(100vw - 32px));
  border: 1px solid #2f3d63;
  border-radius: 6px;
  background: linear-gradient(180deg, #12192d, #0b1020);
  box-shadow: 0 18px 40px #0000008c;
  padding: 14px 16px;
}
.dialog-preview h4 {
  margin: 0;
  color: var(--wc3-gold);
  font-size: 1rem;
}
.dialog-preview p {
  margin: 8px 0 0;
  color: #c8d0e8;
  font-size: 0.86rem;
  line-height: 1.45;
}
.dialog-actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
  margin-top: 12px;
}
.dialog-btn {
  border: 1px solid #4a5c86;
  border-radius: 4px;
  background: #121a30;
  color: #dce5fb;
  padding: 6px 11px;
  font-family: inherit;
  cursor: pointer;
}
.dialog-btn:hover {
  border-color: #6780bb;
}
.dialog-btn--secondary {
  border-color: #505a79;
  color: #d4d9e8;
}
.dialog-btn--danger {
  border-color: #8f4a4a;
  background: #2a1418;
  color: #f4d2d2;
}
.chat-preview {
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.chat-log {
  border: 1px solid #1f2a46;
  border-radius: 6px;
  background: #090d18;
  padding: 10px;
  max-height: 170px;
  overflow: auto;
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.chat-line {
  font-size: 0.82rem;
  line-height: 1.35;
}
.chat-from {
  font-weight: 700;
  margin-right: 6px;
}
.chat-line--ally {
  color: #8fc0ff;
}
.chat-line--enemy {
  color: #f29090;
}
.chat-line--system {
  color: #f0d775;
  font-style: italic;
}
.chat-line--whisper {
  color: #c4a4ff;
}
.chat-input-row {
  display: flex;
  gap: 8px;
}
.chat-input-row input {
  flex: 1;
  border: 1px solid #2a3453;
  border-radius: 4px;
  background: #0a0f1c;
  color: #dce5fb;
  font-family: inherit;
  padding: 7px 9px;
}
.chat-input-row button {
  border: 1px solid #43527b;
  border-radius: 4px;
  background: #111a30;
  color: #dce5fb;
  font-family: inherit;
  padding: 7px 12px;
}
.hero-card-stack {
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.hero-card-preview {
  display: flex;
  gap: 12px;
  align-items: flex-start;
  border: 1px solid #2a3554;
  border-radius: 6px;
  background: linear-gradient(180deg, #0d1323, #080d1a);
  padding: 12px;
}
.hero-card-portrait-wrap {
  position: relative;
}
.hero-card-portrait {
  width: 78px;
  height: 78px;
}
.hero-card-level {
  position: absolute;
  right: -6px;
  bottom: -4px;
  min-width: 20px;
  padding: 1px 5px;
  border: 1px solid rgba(255, 212, 18, 0.58);
  border-radius: 10px;
  background: #000c;
  color: var(--wc3-gold);
  font-size: 0.72rem;
  text-align: center;
}
.hero-card-body {
  flex: 1;
  min-width: 0;
}
.hero-card-head h4 {
  margin: 0;
  color: var(--wc3-gold);
  font-size: 1rem;
}
.hero-card-head span {
  color: #9cabcf;
  font-size: 0.78rem;
}
.hero-card-bars {
  margin-top: 8px;
  display: flex;
  flex-direction: column;
  gap: 5px;
}
.hero-card-bar {
  position: relative;
  height: 12px;
  border: 1px solid #2f3f68;
  border-radius: 3px;
  background: #070b14;
  overflow: hidden;
}
.hero-card-bar-fill {
  position: absolute;
  inset: 0 auto 0 0;
  height: 100%;
}
.hero-card-bar-fill--hp {
  background: linear-gradient(90deg, #3abf3a, #58d869);
}
.hero-card-bar-fill--mp {
  background: linear-gradient(90deg, #3a58d2, #6280ff);
}
.hero-card-bar span {
  position: relative;
  display: block;
  text-align: center;
  color: #ecf1ff;
  font-size: 0.66rem;
  line-height: 10px;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}
.hero-card-stats {
  margin-top: 8px;
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 4px 10px;
  color: #b4c0dd;
  font-size: 0.73rem;
}
.hero-card-stats b {
  color: #e0e8ff;
  font-weight: 700;
}
.hero-card-abilities {
  margin-top: 9px;
  display: flex;
  gap: 6px;
}
.hero-card-ability {
  width: 30px;
  height: 30px;
  border: 1px solid #2b3858;
  border-radius: 3px;
  background: #0b1120;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  color: #dbe5ff;
}
.hero-card-ability img {
  width: 100%;
  height: 100%;
  display: block;
}
.hero-card-ability--disabled {
  opacity: 0.45;
}
.hero-card-compact {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  border: 1px solid #283656;
  border-radius: 6px;
  background: #090e1a;
  padding: 7px 9px;
}
.hero-card-compact-portrait {
  width: 44px;
  height: 44px;
}
.hero-card-compact-meta {
  display: flex;
  flex-direction: column;
  line-height: 1.15;
}
.hero-card-compact-meta strong {
  color: #e5ecff;
  font-size: 0.83rem;
}
.hero-card-compact-meta span {
  color: #98a8cb;
  font-size: 0.74rem;
}
.hero-card-skeleton {
  display: flex;
  align-items: center;
  gap: 10px;
  border: 1px solid #20283e;
  border-radius: 6px;
  background: #090d18;
  padding: 10px;
}
.hero-skeleton-avatar {
  width: 46px;
  height: 46px;
  border-radius: 50%;
  background: linear-gradient(90deg, #171f33, #25304d, #171f33);
  background-size: 180% 100%;
  animation: skeleton-shimmer 1.3s linear infinite;
}
.hero-skeleton-lines {
  display: flex;
  flex-direction: column;
  gap: 5px;
  width: 180px;
}
.hero-skeleton-lines span {
  height: 8px;
  border-radius: 4px;
  background: linear-gradient(90deg, #171f33, #25304d, #171f33);
  background-size: 180% 100%;
  animation: skeleton-shimmer 1.3s linear infinite;
}
.hero-skeleton-lines span:nth-child(1) {
  width: 72%;
}
.hero-skeleton-lines span:nth-child(2) {
  width: 94%;
}
.hero-skeleton-lines span:nth-child(3) {
  width: 62%;
}
@keyframes skeleton-shimmer {
  0% {
    background-position: 0% 0;
  }
  to {
    background-position: 180% 0;
  }
}
.esc-checkbox {
  position: relative;
  width: 32px;
  height: 32px;
  border: none;
  padding: 0;
  background: transparent;
  cursor: pointer;
  flex-shrink: 0;
}
.esc-checkbox img {
  width: 100%;
  height: 100%;
  display: block;
  position: absolute;
  inset: 0;
}
.esc-radio {
  position: relative;
  width: 24px;
  height: 24px;
  border: none;
  padding: 0;
  background: transparent;
  cursor: pointer;
  flex-shrink: 0;
}
.esc-radio img {
  width: 100%;
  height: 100%;
  display: block;
  position: absolute;
  inset: 0;
}
@media (max-width: 900px) {
  .viewport {
    padding: calc(4vw + 12px) 16px 14px;
  }
  .footer-worker-unit {
    display: none;
  }
  .token-grid {
    gap: 12px;
  }
  .token-grid-header {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 6px 10px;
    margin-bottom: 0;
  }
  .token-grid-header > :first-child {
    display: none;
  }
  .token-faction-label {
    font-size: 0.64rem;
  }
  .token-grid-row {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 8px;
  }
  .token-name {
    grid-column: 1 / -1;
    font-size: 0.92rem;
    text-align: left;
  }
  .token-swatch {
    min-height: 40px;
  }
  .token-hex {
    font-size: 0.78rem;
  }
  .hero-logo {
    width: min(320px, 55vw);
  }
  .bundle-chart-row {
    grid-template-columns: 100px 132px 45px;
  }
  .bundle-chart {
    --bundle-bar-width: 132px;
  }
}
.borders-category {
  padding: 14px 0 8px;
  border-top: 1px solid rgba(88, 104, 158, 0.45);
}
.borders-category:first-child {
  padding-top: 0;
  border-top: none;
}
.borders-category-title {
  margin: 0 0 2px;
  color: var(--wc3-gold);
  font-size: 0.98rem;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
}
.borders-category-desc {
  margin: 0 0 10px;
  color: #7b818d;
  font-size: 0.82rem;
  line-height: 1.4;
}
.borders-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
  gap: 12px;
}
.border-item {
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
}
.border-thumbnail {
  width: 100%;
  max-width: 156px;
  height: 96px;
  object-fit: contain;
  image-rendering: pixelated;
  background: transparent;
  border-radius: 3px;
}
.border-label {
  color: #e2e9ff;
  font-size: 0.78rem;
  line-height: 1.2;
}
.border-filename {
  color: #5a6080;
  font-size: 0.65rem;
  word-break: break-all;
  line-height: 1.2;
}
.borders-loading {
  color: #7b818d;
  font-size: 0.88rem;
  text-align: center;
  padding: 24px 0;
}
@media (max-width: 640px) {
  .borders-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 10px 8px;
  }
  .border-thumbnail {
    max-width: 132px;
    height: 84px;
  }
  .border-label {
    font-size: 0.74rem;
  }
}
.tooltip-preview-grid {
  justify-items: center;
}

